// Drops media generated by the canvas composer onto the workflow as constant
// nodes. Generation flows through the normal chat pipeline (GlobalChatStore →
// WebSocket chat_message with media_generation), so the assistant reply lands
// in the active thread's message cache. This hook watches that cache and, for
// each freshly arrived assistant message that the composer asked for, turns its
// image/video/audio content into nodetool.constant.{Image,Video,Audio} nodes.

import { useCallback, useEffect, useRef } from "react";
import type { XYPosition } from "@xyflow/react";
import { useNodeStoreRef } from "../../contexts/NodeContext";
import useGlobalChatStore from "../../stores/GlobalChatStore";
import useMetadataStore from "../../stores/MetadataStore";
import type {
  Message,
  MessageImageContent,
  MessageVideoContent,
  MessageAudioContent
} from "../../stores/ApiTypes";

type MediaContentBlock =
  | MessageImageContent
  | MessageVideoContent
  | MessageAudioContent;

const EMPTY_MESSAGES: Message[] = [];

// Where to drop the next batch: just right of the existing graph, top-aligned.
const computeBasePosition = (
  nodes: { position: XYPosition; width?: number | null }[]
): XYPosition => {
  if (nodes.length === 0) {
    return { x: 0, y: 0 };
  }
  let maxRight = -Infinity;
  let minTop = Infinity;
  for (const node of nodes) {
    const width = node.width ?? 200;
    maxRight = Math.max(maxRight, node.position.x + width);
    minTop = Math.min(minTop, node.position.y);
  }
  return {
    x: (Number.isFinite(maxRight) ? maxRight : 0) + 80,
    y: Number.isFinite(minTop) ? minTop : 0
  };
};

const extractMediaBlocks = (
  content: Message["content"]
): MediaContentBlock[] => {
  if (!Array.isArray(content)) {
    return [];
  }
  return content.filter(
    (c): c is MediaContentBlock =>
      c.type === "image_url" || c.type === "video" || c.type === "audio"
  );
};

const blockToConstant = (
  block: MediaContentBlock
): { nodeType: string; value: Record<string, unknown> } | null => {
  if (block.type === "image_url") {
    const ref = block.image;
    return {
      nodeType: "nodetool.constant.Image",
      value: { type: "image", asset_id: ref.asset_id, uri: ref.uri }
    };
  }
  if (block.type === "video") {
    const ref = block.video;
    return {
      nodeType: "nodetool.constant.Video",
      value: { type: "video", asset_id: ref.asset_id, uri: ref.uri }
    };
  }
  const ref = block.audio;
  return {
    nodeType: "nodetool.constant.Audio",
    value: { type: "audio", asset_id: ref.asset_id, uri: ref.uri }
  };
};

export interface GenerationToCanvas {
  /** Tell the watcher to expect one media result and drop it on the canvas. */
  markGenerationStarted: () => void;
}

export const useGenerationToCanvas = (): GenerationToCanvas => {
  const nodeStore = useNodeStoreRef();
  const getMetadata = useMetadataStore((state) => state.getMetadata);

  const currentThreadId = useGlobalChatStore((state) => state.currentThreadId);
  const messages = useGlobalChatStore((state) =>
    state.currentThreadId
      ? state.messageCache[state.currentThreadId] ?? EMPTY_MESSAGES
      : EMPTY_MESSAGES
  );

  // Message keys already accounted for, so history (and our own optimistic user
  // echo) never spawns nodes. Re-seeded whenever the active thread changes.
  const seenKeys = useRef<Set<string>>(new Set());
  const seededThread = useRef<string | null>(null);
  // Number of media results still expected from composer-initiated requests.
  const pending = useRef(0);

  const markGenerationStarted = useCallback(() => {
    pending.current += 1;
  }, []);

  const dropBlocks = useCallback(
    (blocks: MediaContentBlock[]) => {
      const { nodes, createNode, addNode } = nodeStore.getState();
      const base = computeBasePosition(nodes);
      blocks.forEach((block, i) => {
        const constant = blockToConstant(block);
        if (!constant) {
          return;
        }
        const metadata = getMetadata(constant.nodeType);
        if (!metadata) {
          console.warn(
            `Cannot drop generated media: metadata for ${constant.nodeType} is missing`
          );
          return;
        }
        const position: XYPosition = {
          x: base.x + (i % 2) * 340,
          y: base.y + Math.floor(i / 2) * 300
        };
        const node = createNode(metadata, position);
        node.data.properties.value = constant.value;
        addNode(node);
      });
    },
    [nodeStore, getMetadata]
  );

  useEffect(() => {
    const key = (m: Message, i: number) => m.id ?? `${currentThreadId}:${i}`;

    // First sight of a thread: record everything as seen without dropping so
    // pre-existing media (or a thread switch) doesn't dump old assets.
    if (seededThread.current !== currentThreadId) {
      seenKeys.current = new Set(messages.map(key));
      seededThread.current = currentThreadId;
      return;
    }

    messages.forEach((message, i) => {
      const k = key(message, i);
      if (seenKeys.current.has(k)) {
        return;
      }
      seenKeys.current.add(k);
      if (message.role !== "assistant" || pending.current <= 0) {
        return;
      }
      const blocks = extractMediaBlocks(message.content);
      if (blocks.length === 0) {
        return;
      }
      pending.current -= 1;
      dropBlocks(blocks);
    });
  }, [messages, currentThreadId, dropBlocks]);

  return { markGenerationStarted };
};
